   171→    fn sample_averaged<PIN>(
   172→        adc: &mut Adc<'static, ADC1<'static>, Blocking>,
   173→        pin: &mut AdcPin<PIN, ADC1<'static>, AdcCalCurve<ADC1<'static>>>,
   174→    ) -> Result<u16, ()>
   175→    where
   176→        PIN: esp_hal::analog::adc::AdcChannel,
   177→    {
   178→        let mut sum = 0u32;
   179→        for _ in 0..ADC_OVERSAMPLE {
   180→            sum += nb::block!(adc.read_oneshot(pin)).map_err(|_| ())? as u32;
   181→        }
   182→        Ok((sum / ADC_OVERSAMPLE) as u16)
   183→    }
