   411→    unsafe fn write_pd_dirent(buf: *mut u8, entry: &PdDirEntry) {
   412→        let dirent = &mut *buf.cast::<PdDirent>();
   413→        *dirent = PdDirent {
   414→            name: [0u8; 256],
   415→            entry_type: match entry.entry_type {
   416→                EntryType::File => PD_FTYPE_FILE,
   417→                EntryType::Directory => PD_FTYPE_DIR,
   418→            },
   419→            size: entry.size,
   420→        };
   421→        let mut name = [0u8; 13];
   422→        let len = format_app_name(&entry.name, &mut name);
   423→        dirent.name[..len].copy_from_slice(&name[..len]);
   424→    }
