   435→    // ── F9: Launcher + app-load Embassy task ──────────────────────────────────
   436→    #[embassy_executor::task]
   437→    async fn launcher_task(_spawner: Spawner) {
   438→        unsafe {
   439→            if TRANSPORT_PTR.is_null() || LAUNCHER_BUF_PTR.is_null() {
   440→                loop {
   441→                    spin_loop();
   442→                }
   443→            }
   444→
   445→            let launcher_buf = &mut *LAUNCHER_BUF_PTR;
   446→
   447→            if BUTTON_DIAGNOSTIC_MODE {
   448→                let mut last_event = None;
   449→                let mut last_snapshot = ButtonDiagSnapshot {
   450→                    gpio1_mv: u16::MAX,
   451→                    gpio2_mv: u16::MAX,
   452→                    gpio1_decoded: None,
   453→                    gpio2_decoded: None,
   454→                    stable: None,
   455→                    last_event: None,
   456→                };
   457→
   458→                loop {
   459→                    if INPUT_PTR.is_null() {
   460→                        render_boot_placeholder(launcher_buf, BootFailureKind::None);
   461→                        device_refresh_frame(launcher_buf);
   462→                        loop {
   463→                            spin_loop();
   464→                        }
   465→                    }
   466→
   467→                    if let Ok(event) = (&mut *INPUT_PTR).poll() {
   468→                        if let Some(event) = event {
   469→                            last_event = Some(event);
   470→                        }
   471→                    }
   472→
   473→                    let (gpio1_mv, gpio2_mv) = (&*INPUT_PTR).last_samples();
   474→                    let (gpio1_decoded, gpio2_decoded) = (&*INPUT_PTR).last_decoded();
   475→                    let snapshot = ButtonDiagSnapshot {
   476→                        gpio1_mv,
   477→                        gpio2_mv,
   478→                        gpio1_decoded,
   479→                        gpio2_decoded,
   480→                        stable: (&*INPUT_PTR).current_button(),
   481→                        last_event,
   482→                    };
   483→
   484→                    if snapshot != last_snapshot {
   485→                        render_button_diagnostics(launcher_buf, &snapshot);
   486→                        device_refresh_frame(launcher_buf);
   487→                        last_snapshot = snapshot;
   488→                    }
   489→
   490→                    Delay::new().delay_millis(20);
   491→                }
   492→            }
   493→
   494→            if FS_PTR.is_null() || APP_REGION_PTR.is_null() || PDB_BUF_PTR.is_null() {
   495→                render_boot_placeholder(launcher_buf, BOOT_FAILURE);
   496→                device_refresh_frame(launcher_buf);
   497→                loop {
   498→                    spin_loop();
   499→                }
   500→            }
   501→
   502→            let fs = &mut *FS_PTR;
   503→            let app_region = &mut (&mut *APP_REGION_PTR)[..];
   504→            let pdb_buf = &mut (&mut *PDB_BUF_PTR)[..];
   505→
   506→            loop {
   507→                let filename = run_launcher_with_refresh(fs, launcher_buf, device_refresh_frame);
   508→                serial_write_bytes(b"LAUNCH:confirm\n");
   509→                let syscalls = build_syscall_table(app_region.as_ptr() as u32, app_region.len() as u32);
   510→                let mode = if LAUNCH_DRY_RUN {
   511→                    JumpMode::DryRun
   512→                } else {
   513→                    JumpMode::Jump(jump_to_app)
   514→                };
   515→                let _ = load_and_run(fs, &filename, pdb_buf, app_region, &syscalls, mode);
   516→            }
   517→        }
   518→    }
   519→
   520→    #[main]
   521→    fn main() -> ! {
   522→        let config = Config::default().with_cpu_clock(CpuClock::max());
   523→        let peripherals = esp_hal::init(config);
   524→
   525→        // ── G1: USB Serial/JTAG console — must come first so panics can emit ──
   526→        let serial = SERIAL_CELL.init(UsbSerialJtag::new(peripherals.USB_DEVICE));
   527→        // SAFETY: written once before any task or panic handler runs; single-core.
   528→        unsafe {
   529→            SERIAL_PTR = serial as *mut _;
   530→            set_serial_write_fn(device_serial_write);
   531→        }
   532→        esp_println::println!("PaperDOS kernel boot");
   533→
   534→        let adc1 = unsafe { peripherals.ADC1.clone_unchecked() };
   535→        let gpio1 = unsafe { peripherals.GPIO1.clone_unchecked() };
   536→        let gpio2 = unsafe { peripherals.GPIO2.clone_unchecked() };
   537→
   538→        let tx_buf = DmaTxBuf::new(
   539→            TX_DESC.init([DmaDescriptor::EMPTY; 2]),
   540→            TX_BUF.init([0u8; 4096]),
   541→        )
   542→        .unwrap();
   543→        let rx_buf = DmaRxBuf::new(
   544→            RX_DESC.init([DmaDescriptor::EMPTY; 2]),
   545→            RX_BUF.init([0u8; 4096]),
   546→        )
   547→        .unwrap();
   548→
   549→        let mut spi_raw = spi::master::Spi::new(
   550→            peripherals.SPI2,
   551→            SpiConfig::default()
   552→                .with_frequency(Rate::from_khz(400))
   553→                .with_mode(Mode::_0),
   554→        )
   555→        .unwrap()
   556→        .with_sck(peripherals.GPIO8)
   557→        .with_mosi(peripherals.GPIO10)
   558→        .with_miso(peripherals.GPIO7);
   559→        let _ = spi_raw.write(&[0xFF; 10]);
   560→        let spi_bus = spi_raw
   561→            .with_dma(peripherals.DMA_CH0)
   562→            .with_buffers(rx_buf, tx_buf);
   563→        let spi_ref = SPI_BUS_CELL.init(Mutex::new(RefCell::new(spi_bus)));
   564→
   565→        let fs = if BUTTON_DIAGNOSTIC_MODE {
   566→            Err(BootFailureKind::None)
   567→        } else {
   568→            let sd_spi: SdSpiDevice<'static, Delay> = CriticalSectionDevice::new(
   569→                spi_ref,
   570→                DummyCsPin,
   571→                Delay::new(),
   572→            )
   573→            .unwrap();
   574→            DeviceFs::from_spi2(
   575→                sd_spi,
   576→                // SAFETY: GPIO12 is free for SD CS on the X4 in DIO flash mode.
   577→                unsafe { RawOutputPin::new(12) },
   578→                Delay::new(),
   579→            )
   580→            .map_err(|err| map_boot_failure("sd_init", err))
   581→        };
   582→
   583→        let display_spi = CriticalSectionDevice::new(
   584→            spi_ref,
   585→            Output::new(peripherals.GPIO21, Level::High, OutputConfig::default()),
   586→            Delay::new(),
   587→        )
   588→        .unwrap();
   589→        let mut display = X4DisplayTransport::new(
   590→            display_spi,
   591→            peripherals.GPIO4,
   592→            peripherals.GPIO5,
   593→            peripherals.GPIO6,
   594→        );
   595→        emit_reset_preamble(&mut display).unwrap();
   596→        emit_power_init_block(&mut display).unwrap();
   597→        emit_addressing_init_block(&mut display).unwrap();
   598→
   599→        // F8: Store the transport and wire all device globals before spawning tasks.
   600→        let transport_ref = TRANSPORT_CELL.init(display);
   601→        let launcher_buf_ref = LAUNCHER_BUF_CELL.init([0xFF; FRAME_BYTES]);
   602→        let app_region_ref = APP_REGION_CELL.init([0u8; APP_REGION_BYTES]);
   603→        let pdb_buf_ref = PDB_BUF_CELL.init([0u8; PDB_BUF_BYTES]);
   604→        let fs_ref = match fs {
   605→            Ok(fs) => FS_CELL.init(fs) as *mut _,
   606→            Err(failure) => {
   607→                unsafe { BOOT_FAILURE = failure; }
   608→                core::ptr::null_mut()
   609→            }
   610→        };
   611→        // SAFETY: written once here before the executor starts; single-core.
   612→        unsafe {
   613→            TRANSPORT_PTR = transport_ref as *mut _;
   614→            FS_PTR = fs_ref;
   615→            LAUNCHER_BUF_PTR = launcher_buf_ref as *mut _;
   616→            APP_REGION_PTR = app_region_ref as *mut _;
   617→            PDB_BUF_PTR = pdb_buf_ref as *mut _;
   618→        }
   619→
   620→        if BUTTON_DIAGNOSTIC_MODE {
   621→            render_diag_boot_marker(launcher_buf_ref);
   622→            let _ = display_refresh_flush(transport_ref, launcher_buf_ref);
   623→        } else {
   624→            render_launcher_boot_marker(launcher_buf_ref);
   625→            let _ = display_refresh_flush(transport_ref, launcher_buf_ref);
   626→        }
   627→
   628→        let input = X4AdcSource::new(adc1, gpio1, gpio2);
   629→        let input_ref = INPUT_CELL.init(InputPoller::new(input, 2, 100));
   630→
   631→        // SAFETY: each setter is called exactly once at init; no concurrent access.
   632→        unsafe {
   633→            set_display_flush_fn(device_display_flush);
   634→            set_input_get_buttons_fn(device_get_buttons);
   635→            set_input_wait_button_fn(device_wait_button);
   636→            set_fs_opendir_fn(device_opendir);
   637→            set_fs_readdir_fn(device_readdir);
   638→            set_fs_closedir_fn(device_closedir);
   639→            INPUT_PTR = input_ref as *mut _;
   640→        }
   641→
   642→        let timers = TimerGroup::new(peripherals.TIMG0);
   643→        let software_interrupts = SoftwareInterruptControl::new(peripherals.SW_INTERRUPT);
   644→
   645→        esp_rtos::start(timers.timer0, software_interrupts.software_interrupt0);
   646→
   647→        let executor = EXECUTOR.init(esp_rtos::embassy::Executor::new());
   648→        executor.run(|spawner| {
   649→            spawner.must_spawn(launcher_task(spawner));
